<div class="bg-white rounded-xl shadow-md p-6 sticky top-6"><h3 class="text-xl font-bold mb-4">Filtros</h3><form method="get"><div class="mb-4"><label class="block text-sm font-semibold mb-2">Género</label><?php $cats = get_terms(array('taxonomy' => 'genero_libro', 'hide_empty' => true)); if ($cats) : echo '<select name="genero" class="w-full px-4 py-2 border rounded-lg"><option value="">Todos</option>'; foreach ($cats as $cat) echo '<option value="' . $cat->slug . '">' . $cat->name . '</option>'; echo '</select>'; endif; ?></div><div class="mb-4"><label class="block text-sm font-semibold mb-2">Disponibilidad</label><select name="disponible" class="w-full px-4 py-2 border rounded-lg"><option value="">Todos</option><option value="1">Disponibles</option><option value="0">Prestados</option></select></div><button type="submit" class="w-full px-4 py-2 bg-primary text-white rounded-lg">Filtrar</button></form></div>
